        planArgs.put("identityModel",identityModel);
plan.setArguments(planArgs);
        String message = "Create Service Account request submitted successfully!";
        FacesMessage myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO, message, "This is ignored");
        List myMessages = new ArrayList();
        myMessages.add(myMessage);
        httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);

        import sailpoint.object.ProvisioningPlan;  
        import sailpoint.object.ProvisioningPlan.AccountRequest; 
        import sailpoint.object.ProvisioningPlan.AttributeRequest; 
        import sailpoint.object.ProvisioningResult;
        import sailpoint.object.Identity;
        import sailpoint.object.IdentityRequest;
        import sailpoint.tools.Util;
        import sailpoint.tools.Message;

        List plans = project.getPlans();
        ProvisioningResult provResult = null;
        if(!Util.isEmpty(plans)) {
        for(ProvisioningPlan provPlan : plans) {
        provResult = provPlan.getResult();
        if(provResult != null && (!provResult.isCommitted() || !provResult.isFailed())) {
        List accountRequests = provPlan.getAccountRequests();
        if(!Util.isEmpty(accountRequests)) {
        provResult = accountRequests.get(0).getResult();
        }
        	}
        }
	}

        if(provResult != null && !provResult.isCommitted()) {
        workflow.put("provisioningError", "true");
        log.error("Error in Provisioning");
        }

        if(identityRequestId != null) {
        String taskResultId = context.getObjectByName(IdentityRequest.class, identityRequestId).getTaskResultId();
        workflow.put("taskResultId", taskResultId);
        }

import sailpoint.object.Identity;
import sailpoint.tools.Util;

Identity workgroupIdentity = new Identity();
String workgroupName =  "WG-" + identityModel.get("prefix") + identityModel.get("sAMAccountName");
workgroupIdentity.setName(workgroupName); 
workgroupIdentity.setDisplayName(identityModel.get("displayName") + " workgroup");
workgroupIdentity.setWorkgroup(true);
workgroupIdentity.setDescription("Owner of Service Account: " + identityModel.get("prefix") + identityModel.get("sAMAccountName"));

List owners = identityModel.get("accountOwners");
if(!Util.isEmpty(owners)) {
String owner = owners.get(0);
Identity ownerIden = context.getObjectByName(Identity.class, owner);
if(ownerIden != null) {
workgroupIdentity.setOwner(ownerIden);
}
}
context.saveObject(workgroupIdentity);
context.commitTransaction();

return workgroupName;

import sailpoint.object.Identity;
	import sailpoint.tools.Util;

  log.debug("Add Account Owners To Workgroup");
  Identity workgroup = context.getObjectByName(Identity.class, workgroupName);
  if(workgroup != null) {
  List owners = identityModel.get("accountOwners");
  if(!Util.isEmpty(owners)) {
  for(String owner : owners) {
  Identity identity = context.getObjectByName(Identity.class, owner);
  if(identity != null) {
  identity.add(workgroup);
  context.saveObject(identity);
  context.commitTransaction();
 	}
  }
  }
  }

  import sailpoint.object.Identity;
	import sailpoint.tools.Util;

  log.debug("Set Workgroup As Administrator");
  Identity identity = context.getObjectByName(Identity.class,identityName);
  Identity workgroup = context.getObjectByName(Identity.class, workgroupName);
  if(identity != null && workgroup != null) {
  identity.setAdministrator(workgroup);
  context.saveObject(identity);
  context.commitTransaction();
  }

