        log.debug("Creating Audit Event");
		Attributes attributes = new Attributes();
		attributes.put("targetUser", identityName);
		Attributes planArgs = plan.getArguments();
          if(planArgs != null && planArgs.get("identityModel") != null){
          Map identityModel = planArgs.get("identityModel");
		attributes.put("Account Type" , identityModel.get("accountType"));
attributes.put("SAM Account Name" , identityModel.get("sAMAccountName"));
attributes.put("Display Name" , identityModel.get("displayName"));
attributes.put("What system(s) will this account be used with?" , identityModel.get("accountSystem"));
attributes.put("Will this account be used for transferring any data?" , identityModel.get("transfersData"));
attributes.put("If so, would any of this data be considered sensitive (PII, PCI, business PII like internal pricing)?" , identityModel.get("sensitiveData"));
attributes.put("Please provide a business use case and justification for this account." , identityModel.get("businessJustification"));
attributes.put("Can this account be set to only have what admin privileges needed to perform its function while abiding by the concept of 'least privilege'?" , identityModel.get("leastPrivilege"));
attributes.put("Will this account be able to have its password rotated on a cadence?" , identityModel.get("passwordRotation"));
attributes.put("Will this account be used for interactive login to any systems (direct user login with the account credentials)" , identityModel.get("login"));
attributes.put("Expected lifespan of the account (temporary, permanent, or project-specific)." , identityModel.get("requiredPermissions"));
attributes.put("Any security requirements or configurations (e.g., MFA Requirements, Risk Exceptions)?" , identityModel.get("securityRequirements"));
attributes.put("Will this account be used with any systems within the PCI or SOX environments?" , identityModel.get("pciSox"));
attributes.put("Will this account be used for interactive login to any systems" , identityModel.get("securityRequirements1"));
attributes.put("Account Owners" , identityModel.get("accountOwners"));
attributes.put("Description" , identityModel.get("description"));
attributes.put("LOB" , identityModel.get("accountType"));
attributes.put("Application Name" , identityModel.get("applicationName"));
attributes.put("Mail Enabled Account" , identityModel.get("mailEnabled"));
attributes.put("Start Date" , identityModel.get("hiredate"));
attributes.put("LOB Name" , identityModel.get("lobname"));
attributes.put("LOB Number" , identityModel.get("lobnumber"));
		}
		createAuditEvent(launcher, "Service_Account_Audit", attributes);
